mapper.select:
SELECT kp.id AS id, kp.name AS name, kp.difficulty AS difficulty, kp.dimension_id AS dimensionId, kd.name AS dimensionName FROM knowledge_point kp LEFT JOIN knowledge_dimension kd ON kp.dimension_id = kd.id WHERE kp.status = 1 AND kp.id IN
#{id}
ORDER BY kd.sort, kd.name, kp.difficulty, kp.name
